import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import axios from 'axios';
import './Profile.css';

function Profile() {
  const [profile, setProfile] = useState(null);
  const [user, setUser] = useState(null);
  const [isEditing, setIsEditing] = useState(false);
  const [formData, setFormData] = useState({
    full_name: '',
    bio: '',
    skills: '',
    hourly_rate: '',
    availability: true,
    location: ''
  });
  const [loading, setLoading] = useState(true);
  const navigate = useNavigate();

  useEffect(() => {
    const token = localStorage.getItem('access');
    if (!token) {
      navigate('/');
    } else {
      fetchProfile();
    }
  }, [navigate]);

  const fetchProfile = async () => {
    try {
      const token = localStorage.getItem('access');
      
      // Get user info
      const userRes = await axios.get('http://127.0.0.1:8000/api/users/me/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      setUser(userRes.data);
      
      // Get profile
      const profileRes = await axios.get('http://127.0.0.1:8000/api/users/profile/', {
        headers: { Authorization: `Bearer ${token}` }
      });
      
      setProfile(profileRes.data);
      setFormData({
        full_name: profileRes.data.full_name || '',
        bio: profileRes.data.bio || '',
        skills: profileRes.data.skills || '',
        hourly_rate: profileRes.data.hourly_rate || '',
        availability: profileRes.data.availability !== false,
        location: profileRes.data.location || ''
      });
      setLoading(false);
    } catch (error) {
      console.error('Error fetching profile:', error);
      setLoading(false);
    }
  };

  const handleChange = (e) => {
    const value = e.target.type === 'checkbox' ? e.target.checked : e.target.value;
    setFormData({
      ...formData,
      [e.target.name]: value
    });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    try {
      const token = localStorage.getItem('access');
      await axios.patch('http://127.0.0.1:8000/api/users/profile/', formData, {
        headers: { 
          Authorization: `Bearer ${token}`,
          'Content-Type': 'application/json'
        }
      });
      alert('Profile updated successfully!');
      setIsEditing(false);
      fetchProfile();
    } catch (error) {
      console.error('Error updating profile:', error);
      alert('Failed to update profile');
    }
  };

  const handleLogout = () => {
    localStorage.clear();
    navigate('/');
  };

  if (loading) return <div className="loading">Loading profile...</div>;

  return (
    <div className="profile-container">
      <div className="profile-header">
        <h2>My Profile</h2>
        <div className="header-actions">
          <button onClick={handleLogout} className="logout-btn">Logout</button>
        </div>
      </div>

      {!isEditing ? (
        // View Mode
        <div className="profile-card">
          <div className="profile-info">
            <p><strong>Name:</strong> {profile?.full_name || user?.username}</p>
            <p><strong>Email:</strong> {user?.email}</p>
            <p><strong>Role:</strong> {user?.role}</p>
            <p><strong>Bio:</strong> {profile?.bio || 'Not provided'}</p>
            <p><strong>Skills:</strong> {profile?.skills || 'Not provided'}</p>
            {user?.role === 'FREELANCER' && (
              <>
                <p><strong>Hourly Rate:</strong> {profile?.hourly_rate ? `₹${profile.hourly_rate}` : 'Not set'}</p>
                <p><strong>Availability:</strong> {profile?.availability ? 'Available' : 'Not Available'}</p>
              </>
            )}
            <p><strong>Location:</strong> {profile?.location || 'Not provided'}</p>
          </div>
          <button onClick={() => setIsEditing(true)} className="edit-btn">Edit Profile</button>
        </div>
      ) : (
        // Edit Mode
        <form onSubmit={handleSubmit} className="profile-form">
          <div className="form-group">
            <label>Full Name:</label>
            <input
              type="text"
              name="full_name"
              value={formData.full_name}
              onChange={handleChange}
            />
          </div>

          <div className="form-group">
            <label>Bio:</label>
            <textarea
              name="bio"
              rows="4"
              value={formData.bio}
              onChange={handleChange}
              placeholder="Tell about yourself..."
            />
          </div>

          <div className="form-group">
            <label>Skills (comma separated):</label>
            <input
              type="text"
              name="skills"
              value={formData.skills}
              onChange={handleChange}
              placeholder="React, Django, Python"
            />
          </div>

          {user?.role === 'FREELANCER' && (
            <>
              <div className="form-group">
                <label>Hourly Rate (₹):</label>
                <input
                  type="number"
                  name="hourly_rate"
                  value={formData.hourly_rate}
                  onChange={handleChange}
                />
              </div>

              <div className="form-group checkbox">
                <label>
                  <input
                    type="checkbox"
                    name="availability"
                    checked={formData.availability}
                    onChange={handleChange}
                  />
                  Available for work
                </label>
              </div>
            </>
          )}

          <div className="form-group">
            <label>Location:</label>
            <input
              type="text"
              name="location"
              value={formData.location}
              onChange={handleChange}
              placeholder="City, Country"
            />
          </div>

          <div className="form-actions">
            <button type="submit" className="save-btn">Save Changes</button>
            <button type="button" onClick={() => setIsEditing(false)} className="cancel-btn">Cancel</button>
          </div>
        </form>
      )}
    </div>
  );
}

export default Profile;
